#include <bits/stdc++.h>
using namespace std;
priority_queue<int,vector<int>,greater<int>> pq;
int main(){
    long long n,x,y;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>x;
        if(x==1){
            cin>>y;
            pq.push(y);
        }
        else if(x==2){
            cout<<pq.top()<<endl;
        }
        else if(x==3){
            pq.pop();
        }
    }
}
